#define BLOCK_SIZE 256
#define HALO 1
#define IN_RANGE(x, min, max) ((x)>=((min)) && (x)<=((max)))
#define MIN(a, b) ((a)<=((b)) ? (a) : (b))

void dynproc_kernel(
    int iteration,
    const int *gpuWall,
    const int *gpuSrc,
    int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int theHalo,
    int *prev_local,
    int *result_local,
    int *d_outputBuffer)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);

    // Print configuration header once at the start of the first kernel launch
    if (startStep == 0 && bx == 0 && tx == 0) {
        int ph = border / theHalo;
        int sbc = BLOCK_SIZE - ph * theHalo * 2;
        int bc = cols / sbc + (cols % sbc == 0 ? 0 : 1);
        printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",
               ph, cols, border, BLOCK_SIZE, bc, sbc);
    }

    int small_block_cols = BLOCK_SIZE - iteration * theHalo * 2;

    int blkX = small_block_cols * bx - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev_local[tx] = gpuSrc[xidx];
    } else {
        prev_local[tx] = 0;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    bool computed = false;
    int shortest = 0;
    int left = 0;
    int up = 0;
    int right = 0;
    int index = 0;

    for (int i = 0; i < iteration; i++) {
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
            computed = true;
            left = prev_local[W];
            up = prev_local[tx];
            right = prev_local[E];
            shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            index = cols * (startStep + i) + xidx;
            result_local[tx] = shortest + gpuWall[index];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        if (i == iteration - 1)
            break;
        if (computed)
            prev_local[tx] = result_local[tx];
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuResults[xidx] = result_local[tx];
    }
}
